@namespace Lumeo
@inject Services.IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@implements IAsyncDisposable

<div class="@RootClass" @attributes="AdditionalAttributes">
    @if (Attachments is not null)
    {
        <div class="mb-1.5 flex flex-wrap items-center gap-2">
            @Attachments
        </div>
    }

    <textarea id="@_textareaId"
              class="w-full resize-none bg-transparent px-2 py-1.5 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none disabled:cursor-not-allowed disabled:opacity-60"
              style="@TextareaStyle"
              placeholder="@Placeholder"
              rows="1"
              disabled="@IsLoading"
              maxlength="@MaxLengthAttr"
              value="@Value"
              @oninput="HandleInput"
              @onkeydown="HandleKeyDown"></textarea>

    <div class="mt-1 flex items-center justify-between gap-2">
        <div class="flex items-center gap-1 text-muted-foreground">
            @if (ShowAttachButton)
            {
                <button type="button"
                        class="@AttachButtonClass"
                        disabled="@IsLoading"
                        aria-label="@L["PromptInput.Attach"]"
                        @onclick="HandleAttachClick">
                    <SvgGlyph Svg="@(LumeoIcons.Paperclip)" class="h-4 w-4" />
                </button>
            }
            @LeadingContent
        </div>
        <div class="flex items-center gap-2 text-xs text-muted-foreground">
            @if (ShowCharacterCounter)
            {
                <span class="@CounterClass" aria-live="polite">@CounterText</span>
            }
            @TrailingContent
            @if (IsLoading && OnStop.HasDelegate)
            {
                <button type="button"
                        class="@StopButtonClass"
                        aria-label="@L["PromptInput.Stop"]"
                        @onclick="HandleStopClick">
                    <SvgGlyph Svg="@(LumeoIcons.Square)" class="h-4 w-4" />
                </button>
            }
            else
            {
                <button type="button"
                        class="@SendButtonClass"
                        disabled="@IsSendDisabled"
                        aria-label="@L["PromptInput.Send"]"
                        @onclick="HandleSendClick">
                    @if (IsLoading)
                    {
                        <Spinner Size="Lumeo.Size.Sm" Class="text-primary-foreground" />
                    }
                    else
                    {
                        <SvgGlyph Svg="@(LumeoIcons.ArrowUp)" class="h-4 w-4" />
                    }
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }
    [Parameter] public string Placeholder { get; set; } = "Ask anything…";
    [Parameter] public int MaxHeight { get; set; } = 240;
    [Parameter] public int MinHeight { get; set; } = 56;
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public EventCallback<string> OnSend { get; set; }

    /// <summary>
    /// Invoked when the user clicks the Stop button. The Stop button only
    /// replaces Send while <see cref="IsLoading"/> is true AND this callback is
    /// bound — so a consumer that doesn't support cancellation keeps the
    /// previous disabled-spinner behaviour unchanged.
    /// </summary>
    [Parameter] public EventCallback OnStop { get; set; }

    [Parameter] public bool DisableSendOnEmpty { get; set; } = true;

    /// <summary>Optional slot for attachment chips/thumbnails, rendered above the textarea.</summary>
    [Parameter] public RenderFragment? Attachments { get; set; }

    /// <summary>Shows a built-in paperclip attach button in the leading area that invokes <see cref="OnAttach"/>.</summary>
    [Parameter] public bool ShowAttachButton { get; set; }

    /// <summary>Invoked when the built-in attach button is clicked (only when <see cref="ShowAttachButton"/> is true).</summary>
    [Parameter] public EventCallback OnAttach { get; set; }

    /// <summary>
    /// Hard character limit. When set, the textarea enforces <c>maxlength</c> and a
    /// "count/limit" counter is shown. The counter turns into a destructive color
    /// as the limit is approached.
    /// </summary>
    [Parameter] public int? MaxLength { get; set; }

    /// <summary>Forces the character counter to render even when <see cref="MaxLength"/> is not set (shows the raw count).</summary>
    [Parameter] public bool ShowCounter { get; set; }

    [Parameter] public RenderFragment? LeadingContent { get; set; }
    [Parameter] public RenderFragment? TrailingContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _textareaId = LumeoIds.New("prompt-input");
    private bool _autosizeReady;

    // Tracks the value last pushed through autosize so an EXTERNAL Value change
    // (e.g. a consumer clearing the box after send) can be detected in
    // OnAfterRenderAsync and re-autosized — keystroke edits keep this in sync via
    // HandleInput, so only out-of-band changes trigger the extra reflow.
    private string? _lastAutosizedValue;

    private string RootClass =>
        Cx.Merge("flex flex-col rounded-xl border border-border/40 bg-card p-2 shadow-sm transition-colors focus-within:border-ring/60 focus-within:ring-[1.5px] focus-within:ring-ring/40", Class);

    private string TextareaStyle => $"min-height: {MinHeight}px; max-height: {MaxHeight}px;";

    private string SendButtonClass =>
        "inline-flex h-8 w-8 items-center justify-center rounded-lg bg-primary text-primary-foreground transition-colors hover:bg-primary/90 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50";

    // Stop reuses the send footprint but in a neutral/secondary surface so it
    // reads as "halt" rather than "submit".
    private string StopButtonClass =>
        "inline-flex h-8 w-8 items-center justify-center rounded-lg bg-secondary text-secondary-foreground transition-colors hover:bg-secondary/80 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2";

    private string AttachButtonClass =>
        "inline-flex h-8 w-8 items-center justify-center rounded-lg text-muted-foreground transition-colors hover:bg-muted hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50";

    // Counter shows whenever a limit is set or ShowCounter forces it.
    private bool ShowCharacterCounter => ShowCounter || MaxLength.HasValue;
    private int CurrentLength => Value?.Length ?? 0;
    private string CounterText => MaxLength.HasValue ? $"{CurrentLength}/{MaxLength.Value}" : CurrentLength.ToString();

    // Turn destructive within the last 10% (min 10 chars) of the budget.
    private string CounterClass
    {
        get
        {
            if (!MaxLength.HasValue) return "tabular-nums";
            var threshold = MaxLength.Value - Math.Max(10, MaxLength.Value / 10);
            return CurrentLength >= threshold
                ? "tabular-nums font-medium text-destructive"
                : "tabular-nums";
        }
    }

    private string? MaxLengthAttr => MaxLength?.ToString();

    private bool IsSendDisabled =>
        IsLoading || (DisableSendOnEmpty && string.IsNullOrWhiteSpace(Value));

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            try
            {
                _autosizeReady = true;
                await Interop.AiAutosize(_textareaId, MaxHeight);
                _lastAutosizedValue = Value;
                // Suppress the native newline for plain Enter synchronously in JS.
                // The former @onkeydown:preventDefault="_suppressNextKey" bool was
                // applied at render time — one event LATE: the sending Enter still
                // inserted a newline and the next keystroke after a send was
                // swallowed. SkipComposing keeps Enter alive while an IME
                // composition (Japanese/Chinese/Korean) is being confirmed.
                await Interop.RegisterPreventDefaultKeys(
                    _textareaId,
                    new[] { new PreventDefaultKeyRule("Enter", RequireNoModifiers: true, SkipComposing: true) });
                _pdRegistered = true;
            }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { } // JS interop unavailable during prerender
            return;
        }

        // Value can change from OUTSIDE the textarea — e.g. a consumer clearing it
        // after send, or setting it programmatically. HandleInput keeps
        // _lastAutosizedValue in sync for keystroke edits; an external change
        // leaves them divergent, so re-run autosize to drop the now-stale height.
        // autosize is idempotent so the extra call is cheap; gated on
        // _autosizeReady so it never runs before the first render / during prerender.
        if (_autosizeReady && Value != _lastAutosizedValue)
        {
            _lastAutosizedValue = Value;
            try
            {
                await Interop.AiAutosize(_textareaId, MaxHeight);
            }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { }
        }
    }

    // Set only after a successful JS registration so dispose during static
    // prerendering (where OnAfterRenderAsync never ran) doesn't import the
    // JS module just to unregister a handler that never existed (Codex P2).
    private bool _pdRegistered;

    private async Task HandleInput(ChangeEventArgs e)
    {
        Value = e.Value?.ToString();
        await ValueChanged.InvokeAsync(Value);
        if (_autosizeReady)
        {
            _lastAutosizedValue = Value;
            await Interop.AiAutosize(_textareaId, MaxHeight);
        }
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        // Enter confirming an IME composition must never send — the user is
        // committing characters, not the message (matches every AI composer).
        if (e.IsComposing) return;
        // Plain Enter sends — Shift+Enter (and other modifiers) pass through
        // for multiline. The matching newline suppression happens in JS via
        // RegisterPreventDefaultKeys (see OnAfterRenderAsync).
        if (e.Key == "Enter" && !e.ShiftKey && !e.CtrlKey && !e.AltKey && !e.MetaKey)
        {
            await TrySendAsync();
        }
    }

    private Task HandleSendClick() => TrySendAsync();

    private Task HandleStopClick() => OnStop.InvokeAsync();

    private Task HandleAttachClick() => OnAttach.InvokeAsync();

    private async Task TrySendAsync()
    {
        if (IsSendDisabled) return;
        var current = Value ?? string.Empty;
        await OnSend.InvokeAsync(current);
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_textareaId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}
